export function absoluteUrl(path = "/") {
  return new URL(path, site.url).toString();
}

export function absoluteAsset(path) {
  return new URL(path, site.url).toString();
}

export function escapeHtml(value) {
  return String(value)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#39;");
}
